import{_ as o,r as l,o as a,c as i,a as e,d as s,b as t}from"./app-4ca7bf79.js";const _={},r=e("h1",{id:"年轻时要养成的十大好习惯-一个好习惯可以让自己享受一辈子",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#年轻时要养成的十大好习惯-一个好习惯可以让自己享受一辈子","aria-hidden":"true"},"#"),t(" 年轻时要养成的十大好习惯，一个好习惯可以让自己享受一辈子")],-1),d=e("blockquote",null,[e("p",null,"2011-09-28 11:29")],-1),g=e("p",null,"**引导语：**从开始上学时，老师就教导我们，要生活中要养成许多好习惯。如果能把以上生活习惯都习以为常了，那你就离成功不远了！每个人都有孤独的时候。要学会忍受孤独，这样才会成熟起来。",-1),B={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/DD99C119.jpeg",target:"_blank",rel:"noopener noreferrer"},p=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/DD99C119.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),c=e("figcaption",null,"图片",-1),h=e("p",null,[e("strong",null,"1.守时")],-1),A=e("p",null,'买个闹钟，以便按时叫醒你。贪睡和不守时，都将成为你工作和事业上的绊脚石，任何时候都一样。不仅要学会准时，更要学会提前。就如你坐车去某地，沿途的风景很美，你忍不住下车看一看，后来虽然你还是赶到了某地，却不是准时到达。"闹钟"只是一种简单的标志和提示，真正灵活、实用的时间，掌握在每个人的心中。',-1),f={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/F7380AB7.jpeg",target:"_blank",rel:"noopener noreferrer"},u=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/F7380AB7.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),E=e("figcaption",null,"图片",-1),m=e("p",null,"**　2.不要扭扭捏捏**",-1),z=e("p",null,"如果你不喜欢现在的工作，要么辞职不干，要么就闭嘴不言。初出茅庐，往往眼高手低，心高气傲，大事做不了，小事不愿做。不要养成挑三拣四的习惯。不要雨天烦打伞，不带伞又怕淋雨，处处表现出不满的情绪。记住，不做则已，要做就要做好。",-1),y={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/AA1BC6C6.jpeg",target:"_blank",rel:"noopener noreferrer"},b=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/AA1BC6C6.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),v=e("figcaption",null,"图片",-1),j=e("p",null,"**　3.忍受孤独**",-1),w=e("p",null,"每个人都有孤独的时候。要学会忍受孤独，这样才会成熟起来。年轻人嘻嘻哈哈、打打闹闹惯了，到了一个陌生的环境，面对形形色色的人和事，一下子不知所措起来，有时连一个可以倾心说话的地方也没有。这时，千万别浮躁，学会静心，学会忍受孤独。在孤独中思考，在思考中成熟，在成熟中升华。不要因为寂寞而乱了方寸，而去做无聊无益的事情，白白浪费了宝贵的时间。",-1),O={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/C90D94BE.jpeg",target:"_blank",rel:"noopener noreferrer"},Q=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/C90D94BE.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),k=e("figcaption",null,"图片",-1),x=e("p",null,[e("strong",null,"4.要着眼未来")],-1),C=e("p",null,"走运时要做好倒霉的准备。有一天，一只狐狸走到一个葡萄园外，看见里面水灵灵的葡萄垂涎欲滴。可是外面有栅栏挡着，无法进去。于是它一狠心绝食三日，减肥之后，终于钻进葡萄园内饱餐一顿。当它心满意足地想离开葡萄园时，发觉自己吃得太饱，怎么也钻不出栅栏了。相信任何人都不愿做这样的狐狸。退路同样重要。饱带干粮，晴带雨伞，点滴积累，水到渠成。有的东西今天似乎一文不值，但有朝一日也许就会身价百倍。",-1),D={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/54789AE3.jpeg",target:"_blank",rel:"noopener noreferrer"},q=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/54789AE3.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),F=e("figcaption",null,"图片",-1),N=e("p",null,"**　　5.学会坚强**",-1),V=e("p",null,"不要像玻璃那样脆弱。有的人眼睛总盯着自己，所以长不高看不远；总是喜欢怨天尤人，也使别人无比厌烦。没有苦中苦，哪来甜中甜？不要像玻璃那样脆弱，而应像水晶一样透明，太阳一样辉煌，腊梅一样坚强。既然睁开眼睛享受风的清凉，就不要埋怨风中细小的沙粒。",-1),I={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/070F9E32.jpeg",target:"_blank",rel:"noopener noreferrer"},L=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/070F9E32.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),T=e("figcaption",null,"图片",-1),G=e("p",null,"**　　6.管住自己的嘴巴**",-1),H=e("p",null,"管住自己的嘴巴。不要谈论自己，更不要议论别人。谈论自己往往会自大虚伪，在名不副实中失去自己。议论别人往往陷入鸡毛蒜皮的是非口舌中纠缠不清。每天下班后和你的那些同事朋友喝酒聊天可不是件好事，因为，这中间往往会把议论同事、朋友当做话题。背后议论人总是不好的，尤其是议论别人的短处，这些会降低你的人格。",-1),J={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/9318B816.jpeg",target:"_blank",rel:"noopener noreferrer"},K=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/9318B816.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),M=e("figcaption",null,"图片",-1),P=e("p",null,[t("**　7.把握机遇"),e("br"),t(" **")],-1),R=e("p",null,'机会从不会"失掉"，你失掉了，自有别人会得到。不要凡事在天，守株待兔，更不要寄希望于"机会"。机会只不过是相对于充分准备而又善于创造机会的人而言的。也许，你正为失去一个机会而懊悔、埋怨的时候，机会正被你对面那个同样的"倒霉鬼"给抓住了。没有机会，就要创造机会，有了机会，就要巧妙地抓住。',-1),S={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/CC0094A5.jpeg",target:"_blank",rel:"noopener noreferrer"},U=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/CC0094A5.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),W=e("figcaption",null,"图片",-1),X=e("p",null,[e("strong",null,"8.学会与人沟通")],-1),Y=e("p",null,"若电话老是不响，你该打出去。很多时候，电话会给你带来意想不到的收获，它不是花瓶，仅仅成为一种摆设。交了新朋友，别忘了老朋友，朋友多了路好走。交际的一大诀窍就是主动。好的人缘好的口碑，往往助你的事业更上一个台阶。",-1),Z={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/6B097717.jpeg",target:"_blank",rel:"noopener noreferrer"},$=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/6B097717.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),ee=e("figcaption",null,"图片",-1),ne=e("p",null,[e("strong",null,"9.重视爱情")],-1),se=e("p",null,"千万不要因为自己已经到了结婚年龄而草率结婚。想结婚，就要找一个能和你心心相印相辅相携的伴侣。不要因为放纵和游戏而恋爱，不要因为恋爱而影响工作和事业，更不要因一桩草率而失败的婚姻而使人生受阻。感情用事往往会因小失大。",-1),te={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/B53BB697.jpeg",target:"_blank",rel:"noopener noreferrer"},oe=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/B53BB697.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),le=e("figcaption",null,"图片",-1),ae=e("p",null,[e("strong",null,"10.写备忘录")],-1),ie=e("p",null,"写出你一生要做的事情，把单子放在皮夹里，经常拿出来看。人生要有目标，要有计划，要有提醒，要有紧迫感。一个又一个小目标串起来，就成了你一生的大目标。生活富足了，环境改善了，不要忘了皮夹里那张看似薄薄的单子。",-1),_e={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/9424A64B.jpeg",target:"_blank",rel:"noopener noreferrer"},re=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/9424A64B.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),de=e("figcaption",null,"图片",-1),ge=e("p",null,"**编后语：**人生中做到这些，人的品格也会升华，道理很有哲学意义  把平凡的小事做好，将会变得不平凡。学会静心，学会忍受孤独。在孤独中思考，在思考中成熟，在成熟中升华。",-1),Be={href:"https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/Qzone_wyf/Blogs/images/18058CEB.jpeg",target:"_blank",rel:"noopener noreferrer"},pe=e("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/Qzone_wyf/Blogs/images/18058CEB.jpeg",alt:"图片",tabindex:"0",loading:"lazy"},null,-1),ce=e("figcaption",null,"图片",-1),he={href:"http://user.qzone.qq.com/1054991789/share/1309322718",target:"_blank",rel:"noopener noreferrer"},Ae=e("strong",null,"【点击这里教你做人气王，引爆你的空间人气！】",-1),fe=e("blockquote",null,[e("p",null,"评论(0)")],-1);function ue(Ee,me){const n=l("ExternalLinkIcon");return a(),i("div",null,[r,d,g,e("figure",null,[e("a",B,[p,s(n)]),c]),h,A,e("figure",null,[e("a",f,[u,s(n)]),E]),m,z,e("figure",null,[e("a",y,[b,s(n)]),v]),j,w,e("figure",null,[e("a",O,[Q,s(n)]),k]),x,C,e("figure",null,[e("a",D,[q,s(n)]),F]),N,V,e("figure",null,[e("a",I,[L,s(n)]),T]),G,H,e("figure",null,[e("a",J,[K,s(n)]),M]),P,R,e("figure",null,[e("a",S,[U,s(n)]),W]),X,Y,e("figure",null,[e("a",Z,[$,s(n)]),ee]),ne,se,e("figure",null,[e("a",te,[oe,s(n)]),le]),ae,ie,e("figure",null,[e("a",_e,[re,s(n)]),de]),ge,e("figure",null,[e("a",Be,[pe,s(n)]),ce]),e("p",null,[e("a",he,[Ae,s(n)])]),fe])}const ye=o(_,[["render",ue],["__file","080_2011-09-2811_29_转载【年轻时要养成的十大好习惯，一个好习惯可以让自己享受一辈子】.html.vue"]]);export{ye as default};
